void inOrder(Node* root, vector<int> &nodes){
    if(root == NULL)
      return;
    inOrder(root -> left, nodes);
    nodes.push_back(root->val);
    inOrder(root -> right, nodes);
}

class Solution {
  public:
    int kthLargestNode(Node* root, int k) {
        vector<int> nodes;
        inOrder(root, nodes);
        return nodes[(int)nodes.size() - k];
    }
};

