void inOrder(Node* root, int* nodes, int* index) {
    if (root == NULL)
        return;
    inOrder(root->left, nodes, index);
    nodes[(*index)++] = root->val;
    inOrder(root->right, nodes, index);
}

int kthLargestNode(Node* root, int k) {
    int nodes[MAX_NODES];
    int index = 0;
    inOrder(root, nodes, &index);
    if (k > index) {
        printf("Invalid k\n");
        exit(EXIT_FAILURE);
    }
    return nodes[index - k];
}

