function findKthLargest(root, K) {
    let count = 0;
    let result = null;

    function reverseInOrder(node) {
        if (node === null || count >= K) return;

        reverseInOrder(node.right);

        count++;
        if (count === K) {
            result = node.val;
            return;
        }

        reverseInOrder(node.left);
    }

    reverseInOrder(root);
    return result;
}
